The reference solution of that problem in Javascript is 
function solve(edges, online, k) {
    const n = online.length;
    if (n === 1) return 0;
    let maxEdge = 0;
    for (const [u, v, c] of edges) {
        if (c > maxEdge) maxEdge = c;
    }

    function check(mid) {
        const adj = new Map();
        const inDegree = new Array(n).fill(0);
        for (const [u, v, c] of edges) {
            if (c >= mid && online[u] && online[v]) {
                if (!adj.has(u)) adj.set(u, []);
                adj.get(u).push({ v, c });
                inDegree[v]++;
            }
        }

        const queue = [];
        for (let i = 0; i < n; i++) {
            if (inDegree[i] === 0) queue.push(i);
        }

        const topo = [];
        while (queue.length > 0) {
            const u = queue.shift();
            topo.push(u);
            if (adj.has(u)) {
                for (const { v, c } of adj.get(u)) {
                    inDegree[v]--;
                    if (inDegree[v] === 0) queue.push(v);
                }
            }
        }

        const dist = new Array(n).fill(Infinity);
        dist[0] = 0;
        for (const u of topo) {
            if (dist[u] === Infinity) continue;
            if (adj.has(u)) {
                for (const { v, c } of adj.get(u)) {
                    if (dist[u] + c < dist[v]) {
                        dist[v] = dist[u] + c;
                    }
                }
            }
        }

        return dist[n - 1] <= k;
    }

    let low = 0, high = maxEdge;
    let answer = -1;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    return answer;
}

