def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
    val n = online.length
    if (n == 1) return 0L
    var maxEdge = 0L
    for (edge <- edges) {
        if (edge(2) > maxEdge) maxEdge = edge(2)
    }
    var low = 0L
    var high = maxEdge
    var answer = -1L

    def check(mid: Long): Boolean = {
        val adj = scala.collection.mutable.HashMap[Int, List[(Int, Long)]]()
        val inDegree = Array.fill(n)(0)
        for (edge <- edges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            val cost = edge(2)
            if (cost >= mid && online(u) && online(v)) {
                if (!adj.contains(u)) {
                    adj(u) = List()
                }
                adj(u) = adj(u) :+ (v, cost)
                inDegree(v) += 1
            }
        }
        val queue = scala.collection.mutable.Queue[Int]()
        for (i <- 0 until n) {
            if (inDegree(i) == 0) queue.enqueue(i)
        }
        val topo = scala.collection.mutable.ListBuffer[Int]()
        while (queue.nonEmpty) {
            val u = queue.dequeue()
            topo += u
            if (adj.contains(u)) {
                for ((v, cost) <- adj(u)) {
                    inDegree(v) -= 1
                    if (inDegree(v) == 0) queue.enqueue(v)
                }
            }
        }
        val dist = Array.fill(n)(Long.MaxValue)
        dist(0) = 0L
        for (u <- topo) {
            if (dist(u) == Long.MaxValue) {
                // skip
            } else {
                if (adj.contains(u)) {
                    for ((v, cost) <- adj(u)) {
                        if (dist(v) > dist(u) + cost) {
                            dist(v) = dist(u) + cost
                        }
                    }
                }
            }
        }
        dist(n - 1) <= k
    }

    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            answer = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }
    answer
}
