import scala.collection.mutable._

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
    val n = online.length
    if (n == 1) return 0
    var maxEdge = 0L
    for (edge <- edges) {
        val c = edge(2)
        if (c > maxEdge) maxEdge = c
    }

    def check(mid: Long): Boolean = {
        val adj = HashMap[Int, ListBuffer[(Int, Long)]]()
        val inDegree = ArrayBuffer.fill(n)(0)
        for (edge <- edges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            val c = edge(2)
            if (c >= mid && online(u) && online(v)) {
                if (!adj.contains(u)) {
                    adj(u) = ListBuffer()
                }
                adj(u) += (v, c)
                inDegree(v) += 1
            }
        }

        val queue = Queue[Int]()
        for (i <- 0 until n) {
            if (inDegree(i) == 0) queue.enqueue(i)
        }
        val topo = ListBuffer[Int]()
        while (queue.nonEmpty) {
            val u = queue.dequeue()
            topo += u
            if (adj.contains(u)) {
                for ((v, cost) <- adj(u)) {
                    inDegree(v) -= 1
                    if (inDegree(v) == 0) queue.enqueue(v)
                }
            }
        }

        val dist = ArrayBuffer.fill(n)(Long.MaxValue)
        dist(0) = 0
        for (u <- topo) {
            if (dist(u) == Long.MaxValue) {
                continue
            }
            if (adj.contains(u)) {
                for ((v, cost) <- adj(u)) {
                    if (dist(u) + cost < dist(v)) {
                        dist(v) = dist(u) + cost
                    }
                }
            }
        }

        dist(n - 1) <= k
    }

    var low = 0L
    var high = maxEdge
    var answer = -1L
    while (low <= high) {
        val mid = (low + high) / 2
        if (check(mid)) {
            answer = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }
    answer
}
