def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  if (n == 1) return 0L
  val maxEdge = if (edges.isEmpty) 0 else edges.map(_.apply(2)).max

  def check(mid: Long): Boolean = {
    val adj = Array.fill(n)(List[(Int, Long)]())
    val inDegree = Array.fill(n)(0)
    for (edge <- edges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      val c = edge(2)
      if (c >= mid && online(u) && online(v)) {
        adj(u) = adj(u) :+ (v, c)
        inDegree(v) += 1
      }
    }

    val queue = scala.collection.mutable.Queue[Int]()
    for (i <- 0 until n) {
      if (inDegree(i) == 0) queue.enqueue(i)
    }

    val topo = scala.collection.mutable.ListBuffer[Int]()
    while (queue.nonEmpty) {
      val u = queue.dequeue()
      topo += u
      for ((v, c) <- adj(u)) {
        inDegree(v) -= 1
        if (inDegree(v) == 0) queue.enqueue(v)
      }
    }

    val dist = Array.fill(n)(Long.MaxValue)
    dist(0) = 0L
    for (u <- topo) {
      if (dist(u) == Long.MaxValue) {
        // skip
      } else {
        for ((v, c) <- adj(u)) {
          if (dist(u) + c < dist(v)) {
            dist(v) = dist(u) + c
          }
        }
      }
    }

    dist(n - 1) <= k
  }

  var low = 0L
  var high = maxEdge
  var answer = -1L
  while (low <= high) {
    val mid = (low + high) / 2
    if (check(mid)) {
      answer = mid
      low = mid + 1
    } else {
      high = mid - 1
    }
  }
  answer
}
